#include <bits/stdc++.h>
using namespace std;
const int N=2e4+4;
int n,m,k,f[N],siz[N],w[N];
bool dp[N];
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int u,int v){
    int fu=father(u),fv=father(v);
    if(fu!=fv)
        f[fv]=fu,siz[fu]+=siz[fv];
}
int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
        f[i]=i,siz[i]=1;
    while(k--){
        int u,v;
        scanf("%d%d",&u,&v);
        merge(u,v);
    }
    k=0;
    for(int i=1;i<=n;i++)
        if(f[i]==i)
            w[++k]=siz[i];
    dp[0]=1;
    for(int i=1;i<=k;i++)
        for(int j=n;j>=w[i];j--)
            if(dp[j-w[i]])
                dp[j]=1;
    for(int i=0;i<=n;i++){
        if(m>=i && dp[m-i]){
            printf("%d",m-i);
            break;
        }
		if(m+i<=n && dp[m+i]){
            printf("%d",m+i);
            break;
        }
    }
    return 0;
}
